var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"사령관님...... 사령관님!","JPN":"司令官……司令官！","ENG":"Commander... Commander!","TWN":"司令官……司令官！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううむ……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 정신이 드십니까?","JPN":"司令官、気がつきましたか？","ENG":"Commander, are you awake?","TWN":"司令官大人，您醒過來了嗎？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉......?","JPN":"ドミニーク……？","ENG":"Dominic?","TWN":"多明尼克？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내가...... 얼마나 쓰러져 있었지?","JPN":"私は……どのくらい倒れていたんだ？","ENG":"How... How long was I out?","TWN":"我……我昏睡多久了？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이틀 정도입니다.","JPN":"二日くらいです。","ENG":"A couple of days.","TWN":"兩天左右。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이틀이나? 으윽......!!","JPN":"二日も？　ううっ……！！","ENG":"A couple of days?! Ugh!","TWN":"兩天？唔……！！"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"무리하지 마십시오. 부상이 심합니다.","JPN":"ご無理なさらず。ひどいケガをされています。","ENG":"Don't strain yourself. You're badly wounded.","TWN":"請不要太勉強。您受了很重的傷。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"밖은...... 상황은 어떻지?","JPN":"外は……どんな状況だ？","ENG":"The outside... What's the situation?","TWN":"外面……情況如何。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"별로 다를 건 없습니다.","JPN":"特に変わりません。","ENG":"Nothing much has changed.","TWN":"沒什麼特別不同的。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"게임은 여전히 진행 중이고......","JPN":"ゲームは続いていて……","ENG":"The game is still in progress,","TWN":"遊戲仍在持續著。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"클리포트의 마왕들이 접근하는 걸 최대한 저지하는 중입니다.","JPN":"クリフォトの魔王どもの接近をできる限り阻止しているところです。","ENG":"and we're doing our best to keep the Demon Lords of Qliphoth at bay.","TWN":"我們正儘可能地阻止逆卡巴拉魔王們接近。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......벌써 여기까지 왔나 보군요.","JPN":"……もうここまでたどり着いたようですね。","ENG":"It seems they're here already.","TWN":"……看來它們已經到這裡了啊。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"일단은 제가 막아 보지요.","JPN":"ひとまずここは俺が阻止します。","ENG":"I'll try to stop them.","TWN":"總之我去試著阻擋它們吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......부탁하네.","JPN":"……頼むぞ。","ENG":"Thank you.","TWN":"……拜託你了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"별말씀을.","JPN":"お任せを。","ENG":"You're welcome.","TWN":"這沒什麼。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그보다 할 말이 있으면 빨리 마치는 게 좋을 겁니다.","JPN":"それより、話したいことがあれば早く済ませたほうが良いと思います。","ENG":"By the way, if you have something to say, you'd better say it now.","TWN":"比起這個，如果有什麼要說的話，最好還是快說吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"오래 버티지는 못할 것 같으니까요.","JPN":"そう長くは持ちこたえられないはずですから。","ENG":"I doubt I can last too long.","TWN":"感覺你也撐不了多久了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"자, 프리라이더 아가씨들도 밥값할 시간이다. 다들 일어나라고.","JPN":"さあ、フリーライダーのみんなにも飯代分は働いてもらおうか。みんな起きろ。","ENG":"Now, Free Rider ladies. It's time you do your bit. Wake up.","TWN":"那麼，免費騎士的小姐們，也差不多到了結算伙食費的時候，都給我站起來吧。"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"......프리덤 라이더라고 했잖아.","JPN":"……フリーダム・ライダーズと言ったはずよ。","ENG":"Freedom Riders, not Free Riders.","TWN":"……都說是自由騎士了。"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"마지막까지 일부러 그러는 거지, 빌어먹을 군바리 자식아.","JPN":"絶対わざとでしょ、このクソ軍人。","ENG":"You have to do this until the end, don't you? Stupid GI.","TWN":"到最後都要故意叫錯是吧，你們這群當兵的。"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그러게 말이에요, 히로세 씨.","JPN":"ほんとですよね、ヒロセさん。","ENG":"I know, Ms. Hirose.","TWN":"就是說嘛，廣瀨小姐。"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그 개밥 같은 전투식량 좀 나눠 줬다고 마지막까지 생색 내는 것 좀 보세요.","JPN":"あのドッグフードみたいな戦闘食料を分けてくれたからって\\n恩着せがましいにもほどがあります。","ENG":"Just because you shared your lousy combat rations with us doesn't mean you can make fun of us like this!","TWN":"不過是分給我們一些像狗糧一樣的戰鬥食糧，到最後都一副有恩於我們的模樣。"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......이거 미안하군, 아가씨들. 한번만 봐달라고.","JPN":"……これはすまないな。今回だけは目をつむってくれ。","ENG":"My apologies, ladies. But cut me some slack, will you?","TWN":"……那還真是抱歉啊，小姐們，就饒我這一次吧。"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이제 곧 사이 좋게 저승길 친구가 될 텐데 그 전에 조금 친해져 보자는 뜻이었어.","JPN":"もうすぐみんなであの世行きだ。その前にもう少し仲良くなろうってことだよ。","ENG":"We're all going to die soon. I was only trying to lighten up the mood while I could.","TWN":"我原本想說，既然我們馬上就要相親相愛地上路了，在這之前就稍微好好相處吧。"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"됐거든?","JPN":"そんなの結構よ。","ENG":"Stuff it.","TWN":"得了吧？"},"stage":{"bg":"SS_DELTA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일은......? 어떻게 됐지?","JPN":"カイルは……？　どうなったんだ？","ENG":"Kyle... Where is he?","TWN":"凱爾呢？他怎麼樣了？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......전사했습니다.","JPN":"……戦死しました。","ENG":"He's... dead.","TWN":"……戰死了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아는......?","JPN":"シルビアは……？","ENG":"What about Sylvia?","TWN":"希爾維亞呢？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......전사했습니다.","JPN":"……戦死しました。","ENG":"She's dead, too.","TWN":"……戰死了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그래도 우리측 최강의 카드인 제이크 대령이 버티고 있으니까 쉽게 뚫리지는 않을 겁니다.","JPN":"ですが、味方の中で最強のジェイク大佐がいるので、\\n簡単には突破できないはずです。","ENG":"But we've still got Colonel Jake, the ace up our sleeve. He won't let them pass easily.","TWN":"不過我們這邊還有最強王牌——傑克大校頂著，沒有那麼容易被突破。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 정도로 잠재력이 높을 줄 알았다면 신병 시절부터 더 험하게 굴릴 걸 그랬군요, 하하.","JPN":"こんなにも潜在能力が高いと知ってたら、新米の頃からもっと鍛えてやれば良かった、ハハハ。","ENG":"If I knew he'd be so useful, I would have drilled him harder when he was a recruit. Hah hah.","TWN":"早知道他這麼有潛力，我就該在他當新兵的時候，操他操得兇一點了，哈哈。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......정신을 차리셨으니 일단 지하통로로 가시죠.","JPN":"……意識が戻られたので、いったん地下通路へ移動しましょう。","ENG":"Now that you're awake, you should head out to the underground passageway.","TWN":"……既然您已經清醒了，總之先去地下通道吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"운이 좋으면 아직 인근 벙커로 피신할 수 있을 겁니다.","JPN":"運が良ければ、まだ近隣のバンカーへ避難できると思います。","ENG":"If you're lucky, you can get to the nearby bunker without incident.","TWN":"運氣好的話，還可以在附近的掩體避難。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......아니, 가지 않겠네.","JPN":"……いや、やめておく。","ENG":"No, I'm not going.","TWN":"……不，我就不去了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"사령관님?","JPN":"司令官？","ENG":"Commander?","TWN":"司令官？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 늙은 모양이야.","JPN":"私も年をとったみたいだ。","ENG":"I'm getting old.","TWN":"我也上年紀了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"진작 결정을 내렸어야 했는데...... 아마 무서웠나 보지.","JPN":"もっと早く決断すべきだったのに……臆病になっていたようだ。","ENG":"I should have made up my mind earlier, but... I was probably too scared.","TWN":"明明該儘早下定決心的……我大概是在害怕吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"무슨 말씀을 하시는 겁니까?","JPN":"どういう意味でしょうか？","ENG":"What are you talking about?","TWN":"您在說什麼？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 준비하던 그 계획...... 마지막 실험체가 필요하다고 했었지?","JPN":"君が準備していたあの計画……\\n最後の実験体が必要だと言っていたな？","ENG":"That plan of yours. You said you need one more test subject to realize it.","TWN":"你準備的那個計畫……說是需要最後的實驗體對吧？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"안 됩니다!!","JPN":"それはダメです！！","ENG":"No!","TWN":"不行！！"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어차피 이 몸으로는 더 싸울 수도 없어......","JPN":"どうせこの体ではこれ以上戦えない……","ENG":"My body can't handle any more fighting.","TWN":"反正這副身軀也無法再戰鬥了……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면...... 차라리 실험체로 사용하는 게 인류를 위한 일이겠지.","JPN":"だったら……\\nいっそのこと実験体にしたほうが、人類に貢献できるだろう。","ENG":"But it still can contribute to the test for mankind.","TWN":"這樣的話……那還不如當成實驗體，這樣才對人類有貢獻吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"테라사이드 프로젝트는 아직 완성되지 않았습니다!","JPN":"テラサイド・プロジェクトはまだ完成されていません！　","ENG":"Project Terraside is not complete!","TWN":"特拉賽德計畫還沒有完成！"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설사 사령관님의 육체를 사용한다고 해도 남은 인류를 구할 거란 보장은......","JPN":"たとえ司令官の体を借りたとしても、\\n残りの人類を救えるという保証はどこにも……","ENG":"Even with your help, there's no guarantee that it can save the remaining population.","TWN":"就算使用了司令官大人的身體，也無法保證可以救出剩下的人類……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮아......","JPN":"いいんだ……","ENG":"I know, and I'm fine with that.","TWN":"沒關係……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮아, 도미닉. 자네 혼자 모든 책임을 지려고 애쓸 필요는 없어.","JPN":"いいんだ、ドミニーク。君ひとりで全責任を負う必要はないんだよ。","ENG":"It's okay, Dominic. You don't have to be responsible for everything.","TWN":"沒關係的，多明尼克。你沒必要這麼拼命地，把責任都攬到自己身上。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사람은 할 수 있는 데까지만 하면 되는 거야.","JPN":"できるとこまでやればいいんだ。","ENG":"Let's just do the best we can,","TWN":"人只要做到自己力所能及的事就行了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나머지는...... 다음 번 인류에게 맡기면 되겠지.","JPN":"残りは……次の人類に任せるでいいだろう。","ENG":"and leave the rest to the next ones.","TWN":"剩下的……就交給下一代吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우리에게 유산을 물려준 이들이 그러했듯이.","JPN":"我々に遺産を残した先祖のようにな。","ENG":"Just like our predecessors did.","TWN":"就像那些把遺物留給我們的人一樣。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 조금 더 일찍 관리국과 합작을 할 걸 그랬군요. 그랬다면......","JPN":"こうなるとわかってたら、もっと早く管理局と手を組んだのに。\\nそうしていれば……","ENG":"If I knew better, I would have collaborated with the Administration earlier. And if I did...","TWN":"早知如此，我就應該更早一些和管理局合作的。這樣的話……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그들을 너무 믿지 말게나, 도미닉......","JPN":"連中のことをあまり信頼しすぎないほうが良い、ドミニーク……","ENG":"Don't trust it too much, Dominic.","TWN":"不要太相信他們了，多明尼克。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"분명 그들도 인류를 위해서 싸우고는 있지만......","JPN":"彼らも人類のために戦ってはいるが……","ENG":"Sure, it's fighting for humanity just like us,","TWN":"雖然他們看起來確實是在為人類而戰……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어쩐지 내 직감엔 그들의 목적은 엄연히 다른 곳에 있는 것 같다고 느껴지는군.","JPN":"私の直感では、彼らの目的が別のところにある気がする……","ENG":"but I have a feeling that it also has a hidden agenda.","TWN":"但我的直覺告訴我，他們另有目的。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이제 눈이 침침해지는군.","JPN":"そろそろ目が霞んできたな。","ENG":"Now, my eyes are blurry.","TWN":"現在，我的視線開始模糊了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"날 좀 옮겨주게...... 그럴 수 있겠지?","JPN":"私を運んでくれ……いいな？","ENG":"Could you help me move?","TWN":"幫我挪一下……可以嗎？"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Yes, ma'am.","TWN":"……知道了。"},"stage":{"bg":"SS_DELTA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>2049년 12월 25일</color>","JPN":"<color=#ffd34c>2049年12月25日</color>","ENG":"<color=#ffd34c>December 25, 2049</color>","TWN":"<color=#ffd34c>2049年12月25日</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최후 실험체 자원자 - 마리아 안토노프 대장</color>","JPN":"<color=#ffd34c>最後の実験体志願者 - マリア・アントノフ大将</color>","ENG":"<color=#ffd34c>Final Test Subject Volunteer: General Maria Antonov</color>","TWN":"<color=#ffd34c>最終實驗體志願者——瑪麗亞·安東諾夫隊長</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>프로젝트 테라사이드 총책임자 – 도미닉 킹 레지날드 중장</color>","JPN":"<color=#ffd34c>プロジェクト・テラサイドの総責任者ードミニーク・キング・レジナルド中将</color>","ENG":"<color=#ffd34c>Project Terraside Director: Lieutenant General Dominic King Reginald</color>","TWN":"<color=#ffd34c>特拉賽德計畫總負責人——多明尼克·金·雷吉納德中將</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"보여드리기로 약속한 영상은 여기까지입니다.","JPN":"お見せすると約束した動画はここまでです。","ENG":"That's the end of the video I promised to show you.","TWN":"約定好要給你看的影像就是這些了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"감상은 잘 하셨나요?","JPN":"楽しめましたか？","ENG":"How did you like it?","TWN":"感想如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그나저나 연기를 아주 잘 하시던데요.","JPN":"しかし、実にお見事な演技でした。","ENG":"By the way, you're a very good actor.","TWN":"不管怎麼說，您的演技真是不錯呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"의심 한 번 사지 않고 뉴 오하이오를 빼돌리시다니......","JPN":"一度も疑われることなく、ニューオハイオを奪取するなんて。","ENG":"You managed to steal the New Ohio without raising suspicion.","TWN":"竟然完全沒有引起懷疑，就把新俄亥俄凹走了……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"사관 학교가 아니라 배우 학교를 나왔다고 해도 믿을 수 있을 정도였어요.","JPN":"士官学校ではなく俳優養成所出身と言われても信じるほどの演技力かと。","ENG":"I would have believed if you graduated from an acting school instead of the military academy.","TWN":"說您不是軍校畢業的，而是藝校出身的演員，也都會有人信吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그냥 사라져도 됐을 텐데 굳이 이런 연극까지 펼친 걸 보면......","JPN":"黙って消えるという選択肢もあったでしょうに。\\nあえてこんなお芝居までしたのは……","ENG":"You could have just disappeared, but instead, you staged this show.","TWN":"明明可以直接消失，卻還非得來演這麼一齣戲……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신도 꽤나 미움 받기 싫었나 보죠? 예전의 저처럼.","JPN":"あなたも、よほど嫌われたくないんですね？　かつての僕のように。","ENG":"You didn't want her to hate you, did you? I didn't, a long time ago.","TWN":"看來您也很不喜歡被討厭啊？就像過去的我一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"무슨 뜻이지?","JPN":"どういう意味だ？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이제는 결심을 해야 할 때라는 뜻입니다.","JPN":"そろそろ決断すべき時だということです。","ENG":"It's time you make up your mind.","TWN":"意思是，現在是你下定決心的時候了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이미 꽤 오래 전부터 준비를 해 오신 것 같은데......","JPN":"相当前からこの日に備えてきたようですが……","ENG":"I know you've been preparing this for a long time.","TWN":"您似乎很早以前就開始做準備了……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"불멸체 코어까지 당신에게 넘겨준 이상, 아직 어떻게 할지 고민 중이다, 같은 식은 곤란해요.","JPN":"不滅体コアまであなたに渡してるんですから、\\nまだ去就を迷われているようじゃ困りますよ。","ENG":"Now that I've given you the Immortal System Core, I'm not going to wait around any longer.","TWN":"儘管不滅者核心已經交給你了，但我還是很擔心你會怎麼做呢。用一樣的方式我會很困擾的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"물론이다.","JPN":"もちろんだ。","ENG":"I understand.","TWN":"那當然。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"실패는 전생의 나, 한 번으로 충분해.","JPN":"失敗するのは前世の私、一度かぎりで十分だ。","ENG":"I'm not going to make the same mistake I did in my past life.","TWN":"失敗的是上輩子的我，這樣的體驗有一次就夠了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"정확히 말하자면 이건 전생은 아닙니다만......","JPN":"厳密に言うと、これは前世ではありませんが……","ENG":"Technically speaking, that wasn't your past life,","TWN":"準確來說，那也不是上輩子就是了……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뭐, 당신에겐 그거나 그거나 같은 거겠죠.","JPN":"まあ、あなたにとってはそうなのかもしれませんね。","ENG":"but to you, it might as well be.","TWN":"不過，對你來說也都一樣吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럼 가볼까요?","JPN":"では行きましょうか？","ENG":"Now, shall we go?","TWN":"那就走吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아, 참. 그 조직, 이름이 뭐라고 했었죠?","JPN":"あ、そうだ。あの組織、名前何でしたっけ？","ENG":"Oh, right—what did you say that organization's name was?","TWN":"唉，真是的。那個組織，你說它叫什麼名字？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......리플레이서.","JPN":"……リプレイサー。","ENG":"Replacer.","TWN":"……克隆。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 신디케이트다.","JPN":"リプレイサー・シンジケートだ。","ENG":"The Replacer Syndicate.","TWN":"克隆集團。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이봐, 실비아. 상황이 좀 어때?","JPN":"おい、シルビア。様子はどうだ？","ENG":"Hey, Sylvia. How's the situation?","TWN":"喂，希爾維亞。情況如何？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"여전히 똑같아.","JPN":"相変わらずよ。","ENG":"Still the same.","TWN":"老樣子。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그날 일에 대해서는 아무 말씀도 없어.","JPN":"あの日のことについては、だんまり。","ENG":"She hasn't said anything about what happened that day.","TWN":"完全閉口不談那天的事情。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"계속 한숨만 쉬면서 탁자에 앉아 있는데?","JPN":"ため息ばかりつきながら椅子に腰かけてるよ？","ENG":"She's just sitting at the table, sighing.","TWN":"她一直坐在桌旁歎氣唉？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이것 참, 레지날드 부사령관에 뉴 오하이오까지 실종되다니......","JPN":"やれやれ、レジナルド副司令官とニューオハイオが同時に失踪するとはな……","ENG":"Geez, Deputy Commander Reginald disappeared, along with the New Ohio.","TWN":"這還真是，雷吉納德副司令和新俄亥俄竟然都失蹤了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"대체 차원 폭풍 안에서 무슨 일이 있었던 거야?","JPN":"いったい次元の暴風の中で何があったんだ？","ENG":"What the hell happened in that dimensional storm?","TWN":"次元風暴內部究竟發生了什麼啊？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"잠시 비켜주시죠. 여러분.","JPN":"ちょっと道をあけてもらえますか、皆さん。","ENG":"Could you move aside, everyone?","TWN":"請讓一下，各位。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"카일?!","JPN":"カイル！？","ENG":"Kyle?!","TWN":"凱爾？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐야?! 새로운 소식이라도 있어?","JPN":"どうしたの！？　何か新しい情報でもあるの？","ENG":"What? What's the news?","TWN":"什麼？！是有什麼新消息嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런 건 없습니다. 전 상부에서 내려온 명령서를 전달하러 왔을 뿐입니다.","JPN":"そんなのはありません。\\n僕は上層部からの命令書を渡しにきただけですから。","ENG":"Nothing. I only came to deliver orders from HQ.","TWN":"沒有新消息。我只是來轉交上級下達的命令書。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그, 그래? 그럼 전달하는 김에 사령관님께 질문이라도 좀......","JPN":"そ、そうか？　なら、ついでに司令官に質問をちょっと……","ENG":"R-really? Then, while you're at it, could you ask the Commander—","TWN":"是、是嗎？那你報告的時候，順便稍微問問司令官……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다들 여기서 뭘 하고 있나?","JPN":"みんなここで何をしている？","ENG":"What are you all doing here?","TWN":"大家都在這裡做什麼呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사, 사령관님?!","JPN":"し、司令官！？","ENG":"C-Commander?!","TWN":"司、司令官大人？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"마리아 아줌마!!","JPN":"マリアおばさん！！","ENG":"Maria!","TWN":"瑪麗亞大嬸！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"작전도 끝났으니 좀 쉬고들 있게. 한동안은 소집이 없을 거야.","JPN":"作戦も終わったことだし、しばらく休暇をとりたまえ。\\n当分の間招集されることはないはずだ。","ENG":"We just finished an operation. You should go rest. I won't be needing you for a while.","TWN":"作戰也結束了，大家好好休息一下吧。這陣子應該不會有集合了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 그게......","JPN":"いや、それがね……","ENG":"Oh, but...","TWN":"不，這個……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 명령서를 가지고 왔습니다.","JPN":"司令官、命令書をお持ちしました。","ENG":"Commander, I've brought you orders.","TWN":"司令官大人，我把命令書帶來了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"수령 확인에 사인 부탁드립니다.","JPN":"受領欄にサインをお願いします。","ENG":"Please sign here to confirm your receipt.","TWN":"麻煩您簽字確認接收。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"고맙군, 카일. 이건 따로 읽어보도록 하지.","JPN":"すまないな、カイル。これは後で読んでみるとしよう。","ENG":"Thank you, Kyle. I'll read this later.","TWN":"謝謝你，凱爾。這個我之後自己單獨看吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 다들 해산하도록.","JPN":"さあ、みんな解散するように。","ENG":"Everyone, you're dismissed.","TWN":"那大家就解散吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"국방부 명령서","JPN":"国防省命令書","ENG":"Department of Defense Orders","TWN":"國防部命令書"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"수신 – 마리아 안토노프 소장","JPN":"受取人：マリア・アントノフ少将","ENG":"Recipient: Major General Maria Antonov","TWN":"受令者——瑪麗亞·安東諾夫少將。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"기 승인되었던 수신인의 예편 요청을 기각함.","JPN":"承認済みの引退申請を棄却する。","ENG":"The recipient's retirement request has been denied.","TWN":"駁回已批准的受令者退役請求。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"또한 이 명령서를 전달받은 시간을 기점으로 마리아 안토노프 소장을 중장으로, 같은 부대의 제이크 워커 소령을 중령으로 승진 발령함.","JPN":"なお、この命令書を受け取った時刻より、マリア・アントノフ少将を中将に、同じ部隊のジェイク・ウォーカー少佐を中佐に昇進とする。","ENG":"Also as of the time of the receipt of these orders, Major General Maria Antonov has been promoted lieutenant general, and Major Jake Walker in the same unit lieutenant colonel.","TWN":"另外，以收到本命令書的時點開始，瑪麗亞·安東諾夫少將晉升為中將，同隊的傑克·沃克少校晉升為中校。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"보고서에 기재한 델타 세븐 부대의 최종 전술 평가훈련 내용에 대해서는 최고 기밀로 분류, 15년간 문서를 봉인함.","JPN":"報告書に記載したデルタセブンの最終戦術評価訓練の内容は極秘とし、\\n15年間文書を封印する。","ENG":"The Delta Seven unit's final tactical evaluation performance report will be classified as a top secret and sealed against inspection for 15 years.","TWN":"關於報告書所記載的第七三角洲部隊最終評估訓練內容，已被分類為最高機密，並且封檔15年。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"이후 부대 내의 누구에게도 해당 내용을 발설하지 말 것.","JPN":"これ以降、部隊内のいかなる人物に対してもその内容を明かすことを禁じる。","ENG":"Do not disclose this information to anyone in your unit.","TWN":"今後不得向部隊內的任何人洩露相關內容。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이상.","JPN":"以上。","ENG":"The end of the orders.","TWN":"完畢。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 바라던 대로 된 것 같군, 도미닉.","JPN":"君の望み通りだな、ドミニーク。","ENG":"This is just as you wished, Dominic.","TWN":"似乎正如你所期望的那樣啊，多明尼克。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 참...... 이렇게 늙어서도 뜨개질이나 하고 있을 팔자가 아닌 모양이야.","JPN":"私の人生は……こんなに年をとっても\\n編み物を楽しむ暇なんて与えられないようだ。","ENG":"Geez, it figures I'm not destined to spend my retirement days knitting.","TWN":"我也真是……都這把年紀了，看來我命裡就是沒有織毛衣的福氣啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};